const input = $json;
const task = input.task || {};
const description = task.description || '';
const files = task.files || [];
const planDoc = input.plan_document || '';

// Extract library hints from task description, file extensions, and plan
const allText = [description, planDoc, ...files].join(' ').toLowerCase();
const libraries = [];

// Frontend frameworks
if (allText.includes('heroui') || allText.includes('hero ui')) libraries.push('heroui');
if (allText.includes('react') || files.some(f => f.endsWith('.tsx') || f.endsWith('.jsx'))) libraries.push('react');
if (allText.includes('tailwind')) libraries.push('tailwindcss');
if (allText.includes('vite')) libraries.push('vite');
if (allText.includes('nextjs') || allText.includes('next.js')) libraries.push('nextjs');

// Backend
if (allText.includes('express')) libraries.push('express');
if (allText.includes('prisma')) libraries.push('prisma');
if (allText.includes('drizzle')) libraries.push('drizzle');
if (allText.includes('fastify')) libraries.push('fastify');
if (allText.includes('hono')) libraries.push('hono');

// Utilities
if (allText.includes('zod')) libraries.push('zod');
if (allText.includes('trpc') || allText.includes('t3')) libraries.push('trpc');
if (allText.includes('framer-motion') || allText.includes('framer motion')) libraries.push('framer-motion');

// Deduplicate
const unique = [...new Set(libraries)];

// Limit to top 3 most relevant (prioritize order they were found)
const topLibs = unique.slice(0, 3);

return [{ json: { ...input, _libraries: topLibs } }];

const input = $('Extract Libraries').first().json;
const libraries = input._libraries || [];
const response = $json;

// Extract session ID from headers
const headers = response.headers || {};
const sessionId = headers['mcp-session-id'] || '';

if (!sessionId || libraries.length === 0) {
  // No session or no libraries — skip research
  const trigger = $('Execute Workflow Trigger').first().json;
  return [{ json: { ...trigger, _reference: '', _skip: true } }];
}

// Build resolve requests for each library
const resolveRequests = libraries.map((lib, i) => ({
  jsonrpc: '2.0',
  id: i + 10,
  method: 'tools/call',
  params: {
    name: 'resolve-library-id',
    arguments: { libraryName: lib }
  }
}));

return [{ json: { _sessionId: sessionId, _libraries: libraries, _resolveRequests: resolveRequests, _requestIndex: 0, _resolvedIds: [] } }];

// Resolve all libraries and fetch docs in one code node using $helpers
const input = $json;
const sessionId = input._sessionId;
const libraries = input._libraries || [];
const resolveRequests = input._resolveRequests || [];

const mcpUrl = 'http://docky:8811/mcp';
const headers = { 'Content-Type': 'application/json', 'Mcp-Session-Id': sessionId };

function parseSseJson(text) {
  const lines = text.split('\n');
  for (const line of lines) {
    if (line.startsWith('data:')) {
      try { return JSON.parse(line.substring(5).trim()); } catch(e) {}
    }
  }
  try { return JSON.parse(text); } catch(e) { return null; }
}

const allDocs = [];

for (let i = 0; i < resolveRequests.length; i++) {
  try {
    // Resolve library ID
    const resolveRes = await fetch(mcpUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify(resolveRequests[i])
    });
    const resolveText = await resolveRes.text();
    const resolveData = parseSseJson(resolveText);

    if (!resolveData?.result?.content?.[0]?.text) continue;
    const resolveContent = resolveData.result.content[0].text;

    // Parse library ID from response
    let libraryId = '';
    const idMatch = resolveContent.match(/\/[\w/.-]+/);
    if (idMatch) libraryId = idMatch[0];
    if (!libraryId) continue;

    // Fetch docs
    const docsReq = {
      jsonrpc: '2.0',
      id: 100 + i,
      method: 'tools/call',
      params: {
        name: 'get-library-docs',
        arguments: {
          context7CompatibleLibraryID: libraryId,
          tokens: 5000
        }
      }
    };

    const docsRes = await fetch(mcpUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify(docsReq)
    });
    const docsText = await docsRes.text();
    const docsData = parseSseJson(docsText);

    if (docsData?.result?.content?.[0]?.text) {
      allDocs.push(`## ${libraries[i]} Documentation\n\n${docsData.result.content[0].text}`);
    }
  } catch(e) {
    // Skip failed libraries
  }
}

const reference = allDocs.join('\n\n---\n\n');
const trigger = $('Execute Workflow Trigger').first().json;
return [{ json: { ...trigger, _reference: reference } }];

// Pass through trigger data with empty reference
const trigger = $('Execute Workflow Trigger').first().json;
return [{ json: { ...trigger, _reference: '' } }];
